import { AppBar, Avatar, Box, Button, Container, IconButton, Menu, MenuItem, ThemeProvider, Toolbar, Tooltip, Typography, createTheme } from '@mui/material';
import MenuIcon from '@mui/icons-material/Menu';
import AdbIcon from '@mui/icons-material/Adb';
import './header.css';
import { useState } from 'react';
import { green, lightBlue } from '@mui/material/colors';

const pages = ['Seasons', 'Players'];

const theme = createTheme({
    palette: {
      primary: green,
      secondary: lightBlue,
    },
  });

const Header = () => {

    const [anchorElNav, setAnchorElNav] = useState<null | HTMLElement>(null);    
  
    const handleOpenNavMenu = (event: React.MouseEvent<HTMLElement>) => {
      setAnchorElNav(event.currentTarget);
    };    
    const handleCloseNavMenu = () => {
      setAnchorElNav(null);
    };  
    
    return(        
        <ThemeProvider theme={theme}>
        <AppBar position="static">
            <Container>
            <Toolbar >                
                <Typography variant="h6" noWrap component="a" href="/Home"
                    sx={{
                        mr: 2,
                        display: { xs: 'none', md: 'flex' },
                        fontFamily: 'monospace',
                        fontWeight: 700,
                        letterSpacing: '.3rem',
                        color: 'white',
                        textDecoration: 'none',
                    }}
                >
                NPTFC
                </Typography>

                <Box sx={{ flexGrow: 1, display: { xs: 'flex', md: 'none' } }}>
                    <IconButton
                        size="large"
                        aria-label="account of current user"
                        aria-controls="menu-appbar"
                        aria-haspopup="true"
                        onClick={handleOpenNavMenu}
                        color="inherit"                        
                    >
                        <MenuIcon />
                    </IconButton>
                    <Menu
                        id="menu-appbar"
                        anchorEl={anchorElNav}
                        anchorOrigin={{
                        vertical: 'bottom',
                        horizontal: 'left',
                        }}
                        keepMounted
                        transformOrigin={{
                            vertical: 'top',
                            horizontal: 'left',
                        }}
                        open={Boolean(anchorElNav)}
                        onClose={handleCloseNavMenu}
                        sx={{
                        display: { xs: 'block', md: 'none' },
                        }}
                    >
                        {pages.map((page) => (
                            <MenuItem key={page} >
                                <Typography component="a" href="/Home" textAlign="center" sx={{
                        mr: 2,
                        display: { xs: 'flex', md: 'none' },
                        flexGrow: 1,
                        color: 'inherit',
                        textDecoration: 'none',
                    }}>{page}</Typography>
                            </MenuItem>
                        ))}
                    </Menu>
                </Box>
                <AdbIcon sx={{ display: { xs: 'flex', md: 'none' }, mr: 1 }} />
                <Typography
                    variant="h5"
                    noWrap
                    component="a"
                    href="/Home"
                    sx={{
                        mr: 2,
                        display: { xs: 'flex', md: 'none' },
                        flexGrow: 1,
                        fontFamily: 'monospace',
                        fontWeight: 700,
                        letterSpacing: '.3rem',
                        color: 'inherit',
                        textDecoration: 'none',
                    }}
                    >
                    NPTFC
                </Typography>

                {/* This is only visible if we are > xs window size */}
                <Box sx={{ flexGrow: 1, display: { xs: 'none', md: 'flex' } }}>
                    {pages.map((page) => (
                        <Button
                        key={page}
                        onClick={handleCloseNavMenu}
                        href="/Home"
                        sx={{ my: 2, color: 'white', display: 'block' }}
                        >
                        {page}
                        </Button>
                    ))}
                </Box>

                <Box sx={{ flexGrow: 0 }}>
                    <IconButton>
                        <Avatar alt="NPTFC" src="/static/images/avatar/2.jpg" />
                    </IconButton>
                </Box>
            </Toolbar>
            </Container>
      </AppBar>    
      </ThemeProvider>
    );
}
export default Header;
